import React, { useEffect, useState } from 'react';
import { View, Text, TextInput, TouchableOpacity, Alert, Platform, StyleSheet, ActivityIndicator } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const AUTH_KEY = 'authenticated';
const USERNAME_KEY = 'username';
const PASSWORD_KEY = 'password';

const rnBiometrics = new ReactNativeBiometrics();

const LoginScreen = ({ onLoginSuccess }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loadingBio, setLoadingBio] = useState(false);
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);
  const [biometryType, setBiometryType] = useState(null);

  useEffect(() => {
    checkBiometrics();
  }, []);

  const checkBiometrics = async () => {
    try {
      const { available, biometryType } = await rnBiometrics.isSensorAvailable();
      setBiometricsAvailable(available);
      setBiometryType(biometryType);
    } catch (e) {
      setBiometricsAvailable(false);
      setBiometryType(null);
    }
  };

  const handleBiometricLogin = async () => {
    try {
      setLoadingBio(true);
      const { success } = await rnBiometrics.simplePrompt({
        promptMessage: biometryType === ReactNativeBiometrics.FaceID ? 'Authenticate with Face ID' : 'Authenticate with fingerprint',
        cancelButtonText: 'Cancel',
      });

      if (success) {
        await AsyncStorage.setItem(AUTH_KEY, 'true');
        onLoginSuccess();
      }
    } catch (e) {
      Alert.alert('Authentication failed', 'Biometric authentication was not successful.');
    } finally {
      setLoadingBio(false);
    }
  };

  const handlePasswordLogin = async () => {
    try {
      const storedUsername = await AsyncStorage.getItem(USERNAME_KEY);
      const storedPassword = await AsyncStorage.getItem(PASSWORD_KEY);

      if (storedUsername === null || storedPassword === null) {
        Alert.alert('No credentials found', 'Please register first or set up credentials.');
        return;
      }

      if (username === storedUsername && password === storedPassword) {
        await AsyncStorage.setItem(AUTH_KEY, 'true');
        onLoginSuccess();
      } else {
        Alert.alert('Invalid credentials', 'Username or password is incorrect.');
      }
    } catch (e) {
      Alert.alert('Error', 'Unable to login.');
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>

      {biometricsAvailable ? (
        <TouchableOpacity style={styles.bioButton} onPress={handleBiometricLogin} disabled={loadingBio}>
          {loadingBio ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>Login with {biometryType === ReactNativeBiometrics.FaceID ? 'Face ID' : 'Fingerprint'}</Text>}
        </TouchableOpacity>
      ) : null}

      <Text style={styles.orText}>or use password</Text>

      <TextInput
        style={styles.input}
        placeholder="Username"
        value={username}
        onChangeText={setUsername}
        autoCapitalize="none"
      />
      <TextInput
        style={styles.input}
        placeholder="Password"
        value={password}
        onChangeText={setPassword}
        secureTextEntry
      />

      <TouchableOpacity style={styles.loginButton} onPress={handlePasswordLogin}>
        <Text style={styles.buttonText}>Login</Text>
      </TouchableOpacity>
    </View>
  );
};

const HomeScreen = ({ onLogout }) => {
  const handleLogout = async () => {
    await AsyncStorage.removeItem(AUTH_KEY);
    onLogout();
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Home</Text>
      <TouchableOpacity style={styles.loginButton} onPress={handleLogout}>
        <Text style={styles.buttonText}>Logout</Text>
      </TouchableOpacity>
    </View>
  );
};

export default function App() {
  const [authenticated, setAuthenticated] = useState(false);
  const [checkingAuth, setCheckingAuth] = useState(true);

  useEffect(() => {
    bootstrap();
  }, []);

  const bootstrap = async () => {
    try {
      const authFlag = await AsyncStorage.getItem(AUTH_KEY);
      setAuthenticated(authFlag === 'true');
    } finally {
      setCheckingAuth(false);
    }
  };

  if (checkingAuth) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" />
      </View>
    );
  }

  return authenticated ? (
    <HomeScreen onLogout={() => setAuthenticated(false)} />
  ) : (
    <LoginScreen onLoginSuccess={() => setAuthenticated(true)} />
  );
}

